import React, { useEffect, useState, useCallback } from 'react';
import api from '../api/axiosConfig';
import { useTheme } from '../context/ThemeContext';
import ReactMarkdown from 'react-markdown';
import {
  Trash2,
  Download,
  Archive,
  Calendar,
  ShieldCheck,
  Eye,
  X,
  BarChart3,
  AlignLeft
} from 'lucide-react';
import toast from 'react-hot-toast';

const VaultPage = () => {
  const { isDark } = useTheme();
  const [history, setHistory] = useState([]);
  const [loading, setLoading] = useState(true);
  const [selectedItem, setSelectedItem] = useState(null);

  /* ───────── Fetch History ───────── */
  const fetchHistory = useCallback(async () => {
    try {
      const res = await api.get('/portfolio/history');
      const data = res.data?.data || res.data || [];
      setHistory(Array.isArray(data) ? data.filter(item => item && item.id) : []);
    } catch {
      toast.error('DATABASE_OFFLINE: UNABLE_TO_LOAD_VAULT');
    } finally {
      setLoading(false);
    }
  }, []);

  useEffect(() => {
    fetchHistory();
  }, [fetchHistory]);

  /* ───────── Delete ───────── */
  const handleDelete = async (id) => {
    if (!window.confirm('Delete this strategy permanently?')) return;
    try {
      await api.delete(`/portfolio/${id}`);
      setHistory(prev => prev.filter(item => item.id !== id));
      toast.success('DATA_PURGED');
    } catch {
      toast.error('WIPE_FAILURE');
    }
  };

  /* ───────── Download ───────── */
  const handleDownload = async (item) => {
    try {
      const res = await api.post('/portfolio/export', item, {
        responseType: 'blob'
      });
      const blob = new Blob([res.data], { type: 'application/pdf' });
      const url = URL.createObjectURL(blob);
      const a = document.createElement('a');
      a.href = url;
      a.download = `Strategy_${item.id}.pdf`;
      a.click();
      URL.revokeObjectURL(url);
    } catch {
      toast.error('EXPORT_ERROR');
    }
  };

  /* ───────── Modal Scroll Lock ───────── */
  useEffect(() => {
    document.body.style.overflow = selectedItem ? 'hidden' : 'auto';
    return () => (document.body.style.overflow = 'auto');
  }, [selectedItem]);

  if (loading) {
    return <div style={centerStyle}>SYNCHRONIZING_VAULT...</div>;
  }

  return (
    <div className="reveal-node" style={containerStyle}>
      {/* ── Header ── */}
      <div style={headerRow}>
        <h2 style={headerStyle}>
          <Archive size={24} color="var(--accent-primary)" /> Strategy Vault
        </h2>
        <div style={vaultBadge}>
          <BarChart3 size={14} /> {history.length} Nodes
        </div>
      </div>

      {/* ── Strategy List ── */}
      <div style={listStyle}>
        {history.length === 0 && (
          <div style={emptyState}>No saved strategies found.</div>
        )}

        {history.map(item => (
          <div key={item.id} className="vault-card" style={cardStyle}>
            <div style={cardMeta}>
              <div style={{ display: 'flex', gap: '20px' }}>
                <span style={metaText}>
                  <Calendar size={14} />
                  {new Date(item.created_at).toLocaleDateString()}
                </span>
                <span style={riskTag}>
                  <ShieldCheck size={14} />
                  Risk: {item.risk_score ?? 'N/A'}
                </span>
              </div>

              <div style={cardActions}>
                <button style={iconBtn} onClick={() => setSelectedItem(item)} title="View Description">
                  <Eye size={18} />
                </button>
                <button style={iconBtn} onClick={() => handleDownload(item)} title="Export PDF">
                  <Download size={18} />
                </button>
                <button style={deleteBtn} onClick={() => handleDelete(item.id)} title="Delete">
                  <Trash2 size={18} />
                </button>
              </div>
            </div>

            <h4 style={titleStyle}>{item.goal || 'Untitled Strategy'}</h4>

            <p style={labelSmall}>
              <AlignLeft size={12} /> Summary
            </p>

            <div className="markdown-vault">
              <ReactMarkdown>
                {item.summary || '_No summary generated._'}
              </ReactMarkdown>
            </div>
          </div>
        ))}
      </div>

      {/* ── Detail Modal ── */}
      {selectedItem && (
        <div style={modalOverlay(isDark)}>
          <div style={modalContent}>
            <div style={modalHeader}>
              <span style={modalId}>NODE_DATA // ID_{selectedItem.id}</span>
              <button style={closeBtn} onClick={() => setSelectedItem(null)}>
                <X size={20} />
              </button>
            </div>

            <div style={modalBody}>
              <h3 style={modalTitle}>{selectedItem.goal || 'Untitled Strategy'}</h3>

              <p style={modalLabel}>
                <AlignLeft size={14} style={{marginRight: '8px'}} /> AGENTIC_RATIONALE
              </p>

              <div className="markdown-vault modal-description">
                {selectedItem.rationale ? (
                  <ReactMarkdown>{selectedItem.rationale}</ReactMarkdown>
                ) : (
                  <p style={{ opacity: 0.5, fontStyle: 'italic' }}>
                    No execution rationale stored for this node.
                  </p>
                )}
              </div>
            </div>
          </div>
        </div>
      )}

      <style>{`
        /* Global Markdown Styling */
        .markdown-vault p { 
            color: var(--text-primary); 
            font-size: 0.95rem; 
            line-height: 1.6; 
            margin-bottom: 1rem; 
        }
        .markdown-vault h1, .markdown-vault h2 { 
            color: var(--accent-primary); 
            font-size: 1.1rem; 
            margin-top: 1.2rem; 
            text-transform: uppercase;
        }

        /* Modal Specific Fix */
        .modal-description p {
            color: var(--text-primary) !important;
            opacity: 1 !important;
        }

        .vault-card { transition: all 0.2s ease; background: var(--bg-input); }
        .vault-card:hover { border-color: var(--accent-primary) !important; transform: translateY(-2px); }
        .reveal-node { animation: fadeIn 0.3s ease-out; }
        @keyframes fadeIn { from { opacity: 0; transform: translateY(10px); } to { opacity: 1; transform: translateY(0); } }
      `}</style>
    </div>
  );
};

/* ─────────────────────────────── Styles ─────────────────────────────── */

